  (
    'Front Raise And Pullover',
    'front-raise-and-pullover',
    'chest',
    array['back', 'shoulders', 'arms']::text[],
    array['barbell']::text[],
    'raise',
    'beginner',
    'strength',
    true,
    array['Lie on a flat bench while holding a barbell using a palms down grip that is about 15 inches apart.', 'Place the bar on your upper thighs, extend your arms and lock them while keeping a slight bend on the elbows. This will be your starting position.', 'Now raise the weight using a semicircular motion and keeping your arms straight as you inhale. Continue the same movement until the bar is on the other side above your head . (Tip: the bar will travel approximately 180-degrees). At this point your arms should be parallel to the floor with the palms of your hands facing the ceiling.', 'Now return the barbell to the starting position by reversing the motion as you exhale.', 'Repeat for the recommended amount of repetitions.']::text[],
    array['Using more weight or speed than you can control cleanly.', 'Cutting the range of motion short and rushing through the reps.', 'Changing your body position between reps instead of keeping the movement repeatable.']::text[],
