  (
    'Barbell Hack Squat',
    'barbell-hack-squat',
    'legs',
    array['arms']::text[],
    array['barbell']::text[],
    'squat',
    'intermediate',
    'strength',
    true,
    array['Stand up straight while holding a barbell behind you at arms length and your feet at shoulder width. Tip: A shoulder width grip is best with the palms of your hands facing back. You can use wrist wraps for this exercise for a better grip. This will be your starting position.', 'While keeping your head and eyes up and back straight, squat until your upper thighs are parallel to the floor. Breathe in as you slowly go down.', 'Pressing mainly with the heel of the foot and squeezing the thighs, go back up as you breathe out.', 'Repeat for the recommended amount of repetitions.']::text[],
    array['Using more weight or speed than you can control cleanly.', 'Skipping the setup and losing tension before the first rep starts.', 'Changing your body position between reps instead of keeping the movement repeatable.']::text[],
