  (
    'Bradford/Rocky Presses',
    'bradford-rocky-presses',
    'shoulders',
    array['arms']::text[],
    array['barbell']::text[],
    'press',
    'beginner',
    'strength',
    true,
    array['Sit on a Military Press Bench with a bar at shoulder level with a pronated grip (palms facing forward). Tip: Your grip should be wider than shoulder width and it should create a 90-degree angle between the forearm and the upper arm as the barbell goes down. This is your starting position.', 'Once you pick up the barbell with the correct grip, lift the bar up over your head by locking your arms.', 'Now lower the bar down to the back of the head slowly as you inhale.', 'Lift the bar back up to the starting position as you exhale.', 'Lower the bar down to the starting position slowly as you inhale. This is one repetition.', 'Alternate in this manner until you complete the recommended amount of repetitions.']::text[],
    array['Using more weight or speed than you can control cleanly.', 'Letting momentum do the work instead of controlling the full rep.', 'Changing your body position between reps instead of keeping the movement repeatable.']::text[],
    array['Builds strength and control through the shoulders region.', 'Trains multiple joints at once, which can make your sessions more efficient.', 'Gives you a repeatable way to track progress inside Logbook over time.']::text[],
    array['Dumbbell Shoulder Press', 'Seated Cable Shoulder Press', 'Side Lateral Raise']::text[],
    array['Barbell Shoulder Press', 'Clean and Press', 'Standing Barbell Press Behind Neck']::text[],
    'Bradford/Rocky Presses Exercise: Muscles Worked, Tips, and How To Do It',
    'Learn how to do the Bradford/Rocky Presses exercise, which muscles it works, the equipment you need, and common mistakes to avoid.',
    'free-exercise-db',
    'Unlicense'
