  (
    'Clean and Press',
    'clean-and-press',
    'shoulders',
    array['core', 'legs', 'glutes', 'back', 'arms']::text[],
    array['barbell']::text[],
    'press',
    'intermediate',
    'strength',
    true,
    array['Assume a shoulder-width stance, with knees inside the arms. Now while keeping the back flat, bend at the knees and hips so that you can grab the bar with the arms fully extended and a pronated grip that is slightly wider than shoulder width. Point the elbows out to sides. The bar should be close to the shins. Position the shoulders over or slightly ahead of the bar. Establish a flat back posture. This will be your starting position.', 'Begin to pull the bar by extending the knees. Move your hips forward and raise the shoulders at the same rate while keeping the angle of the back constant; continue to lift the bar straight up while keeping it close to your body.', 'As the bar passes the knee, extend at the ankles, knees, and hips forcefully, similar to a jumping motion. As you do so, continue to guide the bar with your hands, shrugging your shoulders and using the momentum from your movement to pull the bar as high as possible. The bar should travel close to your body, and you should keep your elbows out.', 'At maximum elevation, your feet should clear the floor and you should start to pull yourself under the bar. The mechanics of this could change slightly, depending on the weight used. You should descend into a squatting position as you pull yourself under the bar.', 'As the bar hits terminal height, rotate your elbows around and under the bar. Rack the bar across the front of the shoulders while keeping the torso erect and flexing the hips and knees to absorb the weight of the bar.', 'Stand to full height, holding the bar in the clean position.', 'Without moving your feet, press the bar overhead as you exhale. Lower the bar under control .']::text[],
    array['Using more weight or speed than you can control cleanly.', 'Letting momentum do the work instead of controlling the full rep.', 'Changing your body position between reps instead of keeping the movement repeatable.']::text[],
    array['Builds strength and control through the shoulders region.', 'Trains multiple joints at once, which can make your sessions more efficient.', 'Gives you a repeatable way to track progress inside Logbook over time.']::text[],
    array['Dumbbell Shoulder Press', 'Seated Cable Shoulder Press', 'Side Lateral Raise']::text[],
    array['Barbell Shoulder Press', 'Bradford/Rocky Presses', 'Standing Barbell Press Behind Neck']::text[],
    'Clean and Press Exercise: Muscles Worked, Tips, and How To Do It',
    'Learn how to do the Clean and Press exercise, which muscles it works, the equipment you need, and common mistakes to avoid.',
    'free-exercise-db',
    'Unlicense'
  ),
  (
    'Elevated Back Lunge',
    'elevated-back-lunge',
    'legs',
    array['glutes']::text[],
    array['barbell']::text[],
    'single-leg',
    'intermediate',
    'strength',
    true,
    array['Position a bar onto a rack at shoulder height loaded to an appropriate weight. Place a short, raised platform behind you.', 'Rack the bar onto your upper back, keeping your back arched and tight. Step onto your raised platform with both feet. This will be your starting position.', 'Begin by stepping backwards with one leg. Descend by flexing your hips and knees until your knee touches the floor.', 'Pause, and extend through the hips and knees to rise up, returning all the way to the starting position before alternating.']::text[],
    array['Using more weight or speed than you can control cleanly.', 'Cutting the range of motion short and rushing through the reps.', 'Changing your body position between reps instead of keeping the movement repeatable.']::text[],
    array['Builds strength and control through the legs region.', 'Trains multiple joints at once, which can make your sessions more efficient.', 'Gives you a repeatable way to track progress inside Logbook over time.']::text[],
