  (
    'Landmine Linear Jammer',
    'landmine-linear-jammer',
    'shoulders',
    array['core', 'legs', 'chest', 'arms']::text[],
    array['barbell']::text[],
    'general',
    'intermediate',
    'strength',
    true,
    array['Position a bar into landmine or, lacking one, securely anchor it in a corner. Load the bar to an appropriate weight and position the handle attachment on the bar.', 'Raise the bar from the floor, taking the handles to your shoulders. This will be your starting position.', 'In an athletic stance, squat by flexing your hips and setting your hips back, keeping your arms flexed.', 'Reverse the motion by powerfully extending through the hips, knees, and ankles, while also extending the elbows to straighten the arms. This movement should be done explosively, coming out of the squat to full extension as powerfully as possible.', 'Return to the starting position.']::text[],
    array['Using more weight or speed than you can control cleanly.', 'Cutting the range of motion short and rushing through the reps.', 'Changing your body position between reps instead of keeping the movement repeatable.']::text[],
