  (
    'Barbell Ab Rollout - On Knees',
    'barbell-ab-rollout-on-knees',
    'core',
    array['back', 'shoulders']::text[],
    array['barbell']::text[],
    'general',
    'expert',
    'strength',
    true,
    array['Hold an Olympic barbell loaded with 5-10lbs on each side and kneel on the floor.', 'Now place the barbell on the floor in front of you so that you are on all your hands and knees (as in a kneeling push up position). This will be your starting position.', 'Slowly roll the barbell straight forward, stretching your body into a straight position. Tip: Go down as far as you can without touching the floor with your body. Breathe in during this portion of the movement.', 'After a second pause at the stretched position, start pulling yourself back to the starting position as you breathe out. Tip: Go slowly and keep your abs tight at all times.']::text[],
    array['Using more weight or speed than you can control cleanly.', 'Cutting the range of motion short and rushing through the reps.', 'Changing your body position between reps instead of keeping the movement repeatable.']::text[],
    array['Builds strength and control through the core region.', 'Trains multiple joints at once, which can make your sessions more efficient.', 'Gives you a repeatable way to track progress inside Logbook over time.']::text[],
