  (
    'Preacher Curl',
    'preacher-curl',
    'arms',
    array[]::text[],
    array['barbell']::text[],
    'curl',
    'beginner',
    'strength',
    false,
    array['To perform this movement you will need a preacher bench and an E-Z bar. Grab the E-Z curl bar at the close inner handle (either have someone hand you the bar which is preferable or grab the bar from the front bar rest provided by most preacher benches). The palm of your hands should be facing forward and they should be slightly tilted inwards due to the shape of the bar.', 'With the upper arms positioned against the preacher bench pad and the chest against it, hold the E-Z Curl Bar at shoulder length. This will be your starting position.', 'As you breathe in, slowly lower the bar until your upper arm is extended and the biceps is fully stretched.', 'As you exhale, use the biceps to curl the weight up until your biceps is fully contracted and the bar is at shoulder height. Squeeze the biceps hard and hold this position for a second.', 'Repeat for the recommended amount of repetitions.']::text[],
    array['Using more weight or speed than you can control cleanly.', 'Cutting the range of motion short and rushing through the reps.', 'Changing your body position between reps instead of keeping the movement repeatable.']::text[],
    array['Builds strength and control through the arms region.', 'Makes it easier to focus on one area when you want extra practice or volume.', 'Gives you a repeatable way to track progress inside Logbook over time.']::text[],
    array['Dumbbell Bicep Curl', 'Dumbbell One-Arm Triceps Extension', 'Bench Dips']::text[],
    array['Close-Grip Barbell Bench Press', 'Barbell Curl', 'Close-Grip EZ Bar Curl']::text[],
    'Preacher Curl Exercise: Muscles Worked, Tips, and How To Do It',
    'Learn how to do the Preacher Curl exercise, which muscles it works, the equipment you need, and common mistakes to avoid.',
    'free-exercise-db',
    'Unlicense'
  ),
  (
    'Seated Close-Grip Concentration Barbell Curl',
    'seated-close-grip-concentration-barbell-curl',
    'arms',
    array[]::text[],
    array['barbell']::text[],
    'curl',
    'intermediate',
    'strength',
    false,
    array['Sit down on a flat bench with a barbell or E-Z Bar in front of you in between your legs. Your legs should be spread with the knees bent and the feet on the floor.', 'Use your arms to pick the barbell up and place the back of your upper arms on top of your inner thighs (around three and a half inches away from the front of the knee). A supinated grip closer than shoulder width is needed to perform this exercise. Tip: Your arm should be extended at arms length and the barbell should be above the floor. This will be your starting position.', 'While holding the upper arms stationary, curl the weights forward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps.', 'Slowly begin to bring the barbell back to starting position as your breathe in. Tip: Avoid swinging motions at any time.', 'Repeat for the recommended amount of repetitions.']::text[],
    array['Using more weight or speed than you can control cleanly.', 'Cutting the range of motion short and rushing through the reps.', 'Changing your body position between reps instead of keeping the movement repeatable.']::text[],
    array['Builds strength and control through the arms region.', 'Makes it easier to focus on one area when you want extra practice or volume.', 'Gives you a repeatable way to track progress inside Logbook over time.']::text[],
