    array['barbell']::text[],
    'curl',
    'beginner',
    'strength',
    false,
    array['Lie against an incline bench, with your arms holding a barbell and hanging down in a horizontal line. This will be your starting position.', 'While keeping the upper arms stationary, curl the weight up as high as you can while squeezing the biceps. Breathe out as you perform this portion of the movement. Tip: Only the forearms should move. Do not swing the arms.', 'After a second contraction, slowly go back to the starting position as you inhale. Tip: Make sure that you go all of the way down.', 'Repeat for the recommended amount of repetitions.']::text[],
