  (
    'Barbell Side Bend',
    'barbell-side-bend',
    'core',
    array['back']::text[],
    array['barbell']::text[],
    'general',
    'beginner',
    'strength',
    false,
    array['Stand up straight while holding a barbell placed on the back of your shoulders (slightly below the neck). Your feet should be shoulder width apart. This will be your starting position.', 'While keeping your back straight and your head up, bend only at the waist to the right as far as possible. Breathe in as you bend to the side. Then hold for a second and come back up to the starting position as you exhale. Tip: Keep the rest of the body stationary.', 'Now repeat the movement but bending to the left instead. Hold for a second and come back to the starting position.', 'Repeat for the recommended amount of repetitions.']::text[],
    array['Using more weight or speed than you can control cleanly.', 'Cutting the range of motion short and rushing through the reps.', 'Changing your body position between reps instead of keeping the movement repeatable.']::text[],
